import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.client.RestTemplate;

@RestController
public class WebhookHandler {
    
    @Autowired
    private RestTemplate restTemplate;

    // Handler for POST requests to "/handleWebhook"
    @PostMapping("/handleWebhook")
    public ResponseEntity<String> handleWebhook(@RequestBody String url) {
        try {
            // Fetch content from provided URL using RestTemplate
            String response = restTemplate.getForObject(url, String.class);
            
            return ResponseEntity.ok(response);
        } catch (Exception e) {
            // Handle any exceptions and return a 500 Internal Server Error status code with the exception message as body content
            return ResponseEntity.status(500).body(e.getMessage());
        }
    }
}